    radiusM: grid.radiusM,
    halfExtentM: grid.extentM / 2,
    gridSize: grid.gridSize,
    spacingM: grid.spacingM,
    xMin: grid.bounds.westM,
    xMax: grid.bounds.eastM,
    yMin: grid.bounds.southM,
    yMax: grid.bounds.northM,
