    center: { ...grid.center },
    radiusM: grid.radiusM,
    extentM: grid.extentM,
    gridSize: grid.gridSize,
    spacingM: grid.spacingM,
    orientation: { ...grid.orientation },
    bounds: { ...grid.bounds },
    quality: { ...grid.quality },
